/*
 * @method
 * @name oxfun#fetchOHLCV
 * @description fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market
 * @see https://docs.ox.fun/?json#get-v3-candles
 * @param {string} symbol unified symbol of the market to fetch OHLCV data for
 * @param {string} timeframe the length of time each candle represents
 * @param {int} [since] timestamp in ms of the earliest candle to fetch (default 24 hours ago)
 * @param {int} [limit] the maximum amount of candles to fetch (default 200, max 500)
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @param {int} [params.until] timestamp in ms of the latest candle to fetch (default now)
 * @returns {int[][]} A list of candles ordered as timestamp, open, high, low, close, volume
 */
    pub async fn fetch_ohlcv(&mut self, mut symbol: Value, optional_args: &[Value]) -> Value {
        let mut timeframe = get_arg(optional_args, 0, Value::Str("1m".to_string()));
        let mut since = get_arg(optional_args, 1, Value::Null);
        let mut limit = get_arg(optional_args, 2, Value::Null);
        let mut params = get_arg(optional_args, 3, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        self.load_markets(&[]).await;
        let mut market: Value = self.market(symbol.clone());
        timeframe = self.safe_string(self.timeframes.clone(), timeframe.clone(), &[timeframe.clone()]);
        let mut request: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("marketCode".to_string(), get_value(&market, &Value::Str("id".to_string())));
                m.insert("timeframe".to_string(), timeframe.clone());
            m
        });
        if !is_equal(&since, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("startTime".to_string()), since.clone()); // startTime and endTime must be within 7 days of each other
        }
        if !is_equal(&limit, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("limit".to_string()), limit.clone());
        }
        let mut until: Value = self.safe_integer_k(params.clone(), "until", &[]);
        if !is_equal(&until, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("endTime".to_string()), until.clone());
            params = self.omit(params.clone(), Value::Str("until".to_string()), &[]);
        }  else if !is_equal(&since, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("endTime".to_string()), self.sum(&[since.clone(), multiply(&multiply(&multiply(&multiply(&Value::Int(7), &Value::Int(24)), &Value::Int(60)), &Value::Int(60)), &Value::Int(1000))])); // for the exchange not to throw an exception if since is younger than 7 days
        }
        let mut response: Value = self.public_get_v3_candles(&[self.extend(request.clone(), &[params.clone()])]).await;
        //
        //     {
        //         "success": true,
        //         "timeframe": "3600s",
        //         "data": [
        //             {
        //                 "open": "0.03240000",
        //                 "high": "0.03240000",
        //                 "low": "0.03240000",
        //                 "close": "0.03240000",
        //                 "volume": "0",
        //                 "currencyVolume": "0",
        //                 "openedAt": "1714906800000"
        //             },
        //             {
        //                 "open": "0.03240000",
        //                 "high": "0.03240000",
        //                 "low": "0.03240000",
        //                 "close": "0.03240000",
        //                 "volume": "0",
        //                 "currencyVolume": "0",
        //                 "openedAt": "1714903200000"
        //             },
        //             ...
        //         ]
        //     }
        //
        let mut result: Value = self.safe_list_k(response.clone(), "data", &[Value::List(vec![])]);
        return self.parse_ohlc_vs(result.clone(), &[market.clone(), timeframe.clone(), since.clone(), limit.clone()]);

    Value::Null
}

    pub fn parse_ohlcv(&self, mut ohlcv: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        return Value::List(vec![self.safe_integer_k(ohlcv.clone(), "openedAt", &[]), self.safe_number_k(ohlcv.clone(), "open", &[]), self.safe_number_k(ohlcv.clone(), "high", &[]), self.safe_number_k(ohlcv.clone(), "low", &[]), self.safe_number_k(ohlcv.clone(), "close", &[]), self.safe_number_k(ohlcv.clone(), "currencyVolume", &[])]);

    Value::Null
}

