    pub fn parse_trade(&self, mut trade: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        // public fetchTrades
        //
        //     {
        //         "marketCode": "BTC-USD-SWAP-LIN",
        //         "matchPrice": "63900",
        //         "matchQuantity": "1",
        //         "side": "SELL",
        //         "matchType": "TAKER",
        //         "matchedAt": "1714934112352"
        //     }
        //
        //
        // private fetchMyTrades
        //
        //     {
        //         "orderId": "1000104903698",
        //         "clientOrderId": "1715000260094",
        //         "matchId": "400017129522773178",
        //         "marketCode": "ETH-USD-SWAP-LIN",
        //         "side": "BUY",
        //         "matchedQuantity": "0.001",
        //         "matchPrice": "3100.2",
        //         "total": "310.02",
        //         "orderMatchType": "MAKER",
        //         "feeAsset": "OX",
        //         "fee": "0.062004",
        //         "source": "0",
        //         "matchedAt": "1715000267420"
        //     }
        //
        let mut marketId: Value = self.safe_string_k(trade.clone(), "marketCode", &[]);
        market = self.safe_market(&[marketId.clone(), market.clone()]);
        let mut symbol: Value = get_value(&market, &Value::Str("symbol".to_string()));
        let mut timestamp: Value = self.safe_integer_k(trade.clone(), "matchedAt", &[]);
        let mut fee: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("cost".to_string(), self.safe_string_k(trade.clone(), "fee", &[]));
                m.insert("currency".to_string(), self.safe_currency_code(self.safe_string_k(trade.clone(), "feeAsset", &[]), &[]));
            m
        });
        return self.safe_trade(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), self.safe_string_k(trade.clone(), "matchId", &[]));
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("symbol".to_string(), symbol.clone());
        m.insert("type".to_string(), Value::Null);
        m.insert("order".to_string(), self.safe_string_k(trade.clone(), "orderId", &[]));
        m.insert("side".to_string(), self.safe_string_lower(trade.clone(), Value::Str("side".to_string()), &[]));
        m.insert("takerOrMaker".to_string(), self.safe_string_lower2(trade.clone(), Value::Str("matchType".to_string()), Value::Str("orderMatchType".to_string()), &[]));
        m.insert("price".to_string(), self.safe_string_k(trade.clone(), "matchPrice", &[]));
        m.insert("amount".to_string(), self.safe_string2(trade.clone(), Value::Str("matchQuantity".to_string()), Value::Str("matchedQuantity".to_string()), &[]));
        m.insert("cost".to_string(), Value::Null);
        m.insert("fee".to_string(), fee.clone());
        m.insert("info".to_string(), trade.clone());
    m
}), &[market.clone()]);

    Value::Null
}

