    pub fn parse_transaction(&self, mut transaction: Value, optional_args: &[Value]) -> Value {
        let mut currency = get_arg(optional_args, 0, Value::Null);
        //
        //  fetchDeposits
        //     {
        //         "asset":"USDC",
        //         "network":"Ethereum",
        //         "address": "0x998dEc76151FB723963Bd8AFD517687b38D33dE8",
        //         "quantity":"50",
        //         "id":"5914",
        //         "status": "COMPLETED",
        //         "txId":"0xf5e79663830a0c6f94d46638dcfbc134566c12facf1832396f81ecb55d3c75dc",
        //         "creditedAt":"1714821645154"
        //     }
        //
        // fetchWithdrawals
        //     {
        //         id: '968163212989431811',
        //         asset: 'OX',
        //         network: 'Arbitrum',
        //         address: '0x90fc1fB49a4ED8f485dd02A2a1Cf576897f6Bfc9',
        //         quantity: '11.7444',
        //         fee: '1.744400000',
        //         status: 'COMPLETED',
        //         txId: '0xe96b2d128b737fdbca927edf355cff42202e65b0fb960e64ffb9bd68c121f69f',
        //         requestedAt: '1715530365450',
        //         completedAt: '1715530527000'
        //     }
        //
        // withdraw
        //     {
        //         "id": "968364664449302529",
        //         "asset": "OX",
        //         "network": "Arbitrum",
        //         "address": "0x90fc1fB49a4ED8f485dd02A2a1Cf576897f6Bfc9",
        //         "quantity": "10",
        //         "externalFee": false,
        //         "fee": "1.6728",
        //         "status": "PENDING",
        //         "requestedAt": "1715591843616"
        //     }
        //
        let mut id: Value = self.safe_string_k(transaction.clone(), "id", &[]);
        let mut type_var: Value = self.safe_string_k(transaction.clone(), "type", &[]);
        transaction = self.omit(transaction.clone(), Value::Str("type".to_string()), &[]);
        let mut address: Value = Value::Null;
        let mut addressTo: Value = Value::Null;
        let mut status: Value = Value::Null;
        if is_equal(&type_var, &Value::Str("deposit".to_string())) {
            address = self.safe_string_k(transaction.clone(), "address", &[]);
            status = self.parse_deposit_status(self.safe_string_k(transaction.clone(), "status", &[]));
        }  else if is_equal(&type_var, &Value::Str("withdrawal".to_string())) {
            addressTo = self.safe_string_k(transaction.clone(), "address", &[]);
            status = self.parse_withdrawal_status(self.safe_string_k(transaction.clone(), "status", &[]));
        }
        let mut txid: Value = self.safe_string_k(transaction.clone(), "txId", &[]);
        let mut currencyId: Value = self.safe_string_k(transaction.clone(), "asset", &[]);
        let mut code: Value = self.safe_currency_code(currencyId.clone(), &[currency.clone()]);
        let mut network: Value = self.safe_string_k(transaction.clone(), "network", &[]);
        let mut networkCode: Value = self.network_id_to_code(&[network.clone()]);
        let mut timestamp: Value = self.safe_integer2(transaction.clone(), Value::Str("creditedAt".to_string()), Value::Str("requestedAt".to_string()), &[]);
        let mut amount: Value = self.safe_number_k(transaction.clone(), "quantity", &[]);
        let mut feeCost: Value = self.safe_number_k(transaction.clone(), "fee", &[]);
        let mut fee: Value = Value::Null;
        if !is_equal(&feeCost, &Value::Null) {
            fee = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("cost".to_string(), feeCost.clone());
                    m.insert("currency".to_string(), code.clone());
                m
            });
        }
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("info".to_string(), transaction.clone());
        m.insert("id".to_string(), id.clone());
        m.insert("txid".to_string(), txid.clone());
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("network".to_string(), networkCode.clone());
        m.insert("address".to_string(), address.clone());
        m.insert("addressTo".to_string(), addressTo.clone());
        m.insert("addressFrom".to_string(), Value::Null);
        m.insert("tag".to_string(), Value::Null);
        m.insert("tagTo".to_string(), Value::Null);
        m.insert("tagFrom".to_string(), Value::Null);
        m.insert("type".to_string(), type_var.clone());
        m.insert("amount".to_string(), amount.clone());
        m.insert("currency".to_string(), code.clone());
        m.insert("status".to_string(), status.clone());
        m.insert("updated".to_string(), Value::Null);
        m.insert("internal".to_string(), Value::Null);
        m.insert("comment".to_string(), Value::Null);
        m.insert("fee".to_string(), fee.clone());
    m
});

    Value::Null
}

    pub fn parse_deposit_status(&self, mut status: Value) -> Value {
        let mut statuses: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("COMPLETED".to_string(), Value::Str("ok".to_string()));
            m
        });
        return self.safe_string(statuses.clone(), status.clone(), &[status.clone()]);

    Value::Null
}

    pub fn parse_withdrawal_status(&self, mut status: Value) -> Value {
        let mut statuses: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("COMPLETED".to_string(), Value::Str("ok".to_string()));
                m.insert("PROCESSING".to_string(), Value::Str("pending".to_string()));
                m.insert("IN SWEEPING".to_string(), Value::Str("pending".to_string()));
                m.insert("PENDING".to_string(), Value::Str("pending".to_string()));
                m.insert("ON HOLD".to_string(), Value::Str("pending".to_string()));
                m.insert("CANCELED".to_string(), Value::Str("canceled".to_string()));
                m.insert("FAILED".to_string(), Value::Str("failed".to_string()));
            m
        });
        return self.safe_string(statuses.clone(), status.clone(), &[status.clone()]);

    Value::Null
}

