    pub fn create_order_request(&self, mut symbol: Value, mut type_var: Value, mut side: Value, mut amount: Value, optional_args: &[Value]) -> Value {
        let mut price = get_arg(optional_args, 0, Value::Null);
        let mut params = get_arg(optional_args, 1, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        /*
         * @param {string} symbol unified symbol of the market to create an order in
         * @param {string} type 'market', 'limit', 'STOP_LIMIT' or 'STOP_MARKET'
         * @param {string} side 'buy' or 'sell'
         * @param {float} amount how much of currency you want to trade in units of base currency
         * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
         * @param {object} [params] extra parameters specific to the exchange API endpoint
         * @param {int} [params.clientOrderId] a unique id for the order
         * @param {float} [params.cost] the quote quantity that can be used as an alternative for the amount for market buy orders
         * @param {float} [params.triggerPrice] The price at which a trigger order is triggered at
         * @param {float} [params.limitPrice] Limit price for the STOP_LIMIT order
         * @param {bool} [params.postOnly] if true, the order will only be posted if it will be a maker order
         * @param {string} [params.timeInForce] GTC (default), IOC, FOK, PO, MAKER_ONLY or MAKER_ONLY_REPRICE (reprices order to the best maker only price if the specified price were to lead to a taker trade)
         * @param {string} [params.selfTradePrevention] NONE, EXPIRE_MAKER, EXPIRE_TAKER or EXPIRE_BOTH for more info check here {@link https://docs.ox.fun/?json#self-trade-prevention-modes}
         * @param {string} [params.displayQuantity] for an iceberg order, pass both quantity and displayQuantity fields in the order request
         */
        let mut market: Value = self.market(symbol.clone());
        let mut request: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("marketCode".to_string(), get_value(&market, &Value::Str("id".to_string())));
                m.insert("side".to_string(), to_upper(&side));
                m.insert("source".to_string(), Value::Int(1000));
            m
        });
        let mut cost: Value = self.safe_string2(params.clone(), Value::Str("cost".to_string()), Value::Str("amount".to_string()), &[]);
        if !is_equal(&cost, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("amount".to_string()), cost.clone()); // todo costToPrecision
            params = self.omit(params.clone(), Value::List(vec![Value::Str("cost".to_string()), Value::Str("amount".to_string())]), &[]);
        }  else {
            add_element_to_object(&mut request, &Value::Str("quantity".to_string()), amount.clone()); // todo amountToPrecision
        }
        let mut triggerPrice: Value = self.safe_string2(params.clone(), Value::Str("triggerPrice".to_string()), Value::Str("stopPrice".to_string()), &[]);
        let mut orderType: Value = to_upper(&type_var);
        if !is_equal(&triggerPrice, &Value::Null) {
            if is_equal(&orderType, &Value::Str("MARKET".to_string())) {
                orderType = Value::Str("STOP_MARKET".to_string());
            }  else if is_equal(&orderType, &Value::Str("LIMIT".to_string())) {
                orderType = Value::Str("STOP_LIMIT".to_string());
            }
            add_element_to_object(&mut request, &Value::Str("stopPrice".to_string()), triggerPrice.clone()); // todo priceToPrecision
            params = self.omit(params.clone(), Value::List(vec![Value::Str("triggerPrice".to_string()), Value::Str("stopPrice".to_string())]), &[]);
        }
        add_element_to_object(&mut request, &Value::Str("orderType".to_string()), orderType.clone());
        if is_equal(&orderType, &Value::Str("STOP_LIMIT".to_string())) {
            add_element_to_object(&mut request, &Value::Str("limitPrice".to_string()), price.clone()); // todo priceToPrecision
        }  else if !is_equal(&price, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("price".to_string()), price.clone()); // todo priceToPrecision
        }
        let mut postOnly: Value = Value::Null;
        let mut isMarketOrder: Value = Value::Bool(is_true(&(is_equal(&orderType, &Value::Str("MARKET".to_string())))) || is_true(&(is_equal(&orderType, &Value::Str("STOP_MARKET".to_string())))));
        { let __destr_tmp = self.handle_post_only(isMarketOrder.clone(), Value::Bool(false), &[params.clone()]); postOnly = get_value(&__destr_tmp, &Value::Int(0)); params = get_value(&__destr_tmp, &Value::Int(1)); }
        let mut timeInForce: Value = self.safe_string_upper(params.clone(), Value::Str("timeInForce".to_string()), &[]);
        if is_true(&postOnly) && is_true(&(!is_equal(&timeInForce, &Value::Str("MAKER_ONLY_REPRICE".to_string())))) {
            add_element_to_object(&mut request, &Value::Str("timeInForce".to_string()), Value::Str("MAKER_ONLY".to_string()));
        }
        let mut selfTradePrevention: Value = Value::Null;
        { let __destr_tmp = self.handle_option_and_params(params.clone(), Value::Str("createOrder".to_string()), Value::Str("selfTradePrevention".to_string()), &[]); selfTradePrevention = get_value(&__destr_tmp, &Value::Int(0)); params = get_value(&__destr_tmp, &Value::Int(1)); }
        if !is_equal(&selfTradePrevention, &Value::Null) {
            add_element_to_object(&mut request, &Value::Str("selfTradePreventionMode".to_string()), to_upper(&selfTradePrevention));
        }
        return self.extend(request.clone(), &[params.clone()]);

    Value::Null
}

