/*
 * @method
 * @name oxfun#cancelOrders
 * @description cancel multiple orders
 * @see https://docs.ox.fun/?json#delete-v3-orders-cancel
 * @param {string[]} ids order ids
 * @param {string} [symbol] unified market symbol
 * @param {object} [params] extra parameters specific to the exchange API endpoint
 * @param {int} [params.timestamp] in milliseconds
 * @param {int} [params.recvWindow] in milliseconds
 * @param {string} [params.responseType] 'FULL' or 'ACK'
 * @returns {object} an list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
 */
    pub async fn cancel_orders(&mut self, mut ids: Value, optional_args: &[Value]) -> Value {
        let mut symbol = get_arg(optional_args, 0, Value::Null);
        let mut params = get_arg(optional_args, 1, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        if is_equal(&symbol, &Value::Null) {
            panic!("{}", crate::exchange_errors::arguments_required(add(&self.id, &Value::Str(" cancelOrders() requires a symbol argument".to_string()))));
        }
        self.load_markets(&[]).await;
        let mut market: Value = self.market(symbol.clone());
        let mut marketId: Value = get_value(&market, &Value::Str("id".to_string()));
        let mut request: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("timestamp".to_string(), self.milliseconds());
                m.insert("responseType".to_string(), Value::Str("FULL".to_string()));
            m
        });
        let mut orders: Value = Value::List(vec![]);
        {
                        let mut i: Value = Value::Int(0);
            let mut __for_first_992: bool = true;
            while { if !__for_first_992 { i = add(&i, &Value::Int(1)); } __for_first_992 = false; is_less_than(&i, &get_array_length(&ids)) } {
            let mut order: Value = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("marketCode".to_string(), marketId.clone());
                    m.insert("orderId".to_string(), get_value(&ids, &i));
                m
            });
            append_to_array(&mut orders, order.clone());
        }
        }
        add_element_to_object(&mut request, &Value::Str("orders".to_string()), orders.clone());
        let mut response: Value = self.private_delete_v3_orders_cancel(&[self.extend(request.clone(), &[params.clone()])]).await;
        let mut data: Value = self.safe_list_k(response.clone(), "data", &[Value::List(vec![])]);
        return self.parse_orders(data.clone(), &[market.clone()]);

    Value::Null
}

    pub fn parse_order(&self, mut order: Value, optional_args: &[Value]) -> Value {
        let mut market = get_arg(optional_args, 0, Value::Null);
        //
        // accepted market order responseType FULL
        //     {
        //         "notice": "OrderMatched",
        //         "accountId": "106490",
        //         "orderId": "1000109901865",
        //         "submitted": true,
        //         "clientOrderId": "0",
        //         "marketCode": "OX-USDT",
        //         "status": "FILLED",
        //         "side": "SELL",
        //         "isTriggered": false,
        //         "quantity": "150.0",
        //         "amount": "0.0",
        //         "remainQuantity": "0.0",
        //         "matchId": "100017047880451399",
        //         "matchPrice": "0.01465",
        //         "matchQuantity": "150.0",
        //         "feeInstrumentId": "USDT",
        //         "fees": "0.0015382500",
        //         "orderType": "MARKET",
        //         "createdAt": "1715592472236",
        //         "lastMatchedAt": "1715592472200",
        //         "displayQuantity": "150.0"
        //     }
        //
        // accepted limit order responseType FULL
        //     {
        //         "notice": "OrderOpened",
        //         "accountId": "106490",
        //         "orderId": "1000111482406",
        //         "submitted": true,
        //         "clientOrderId": "0",
        //         "marketCode": "ETH-USD-SWAP-LIN",
        //         "status": "OPEN",
        //         "side": "SELL",
        //         "price": "4000.0",
        //         "isTriggered": false,
        //         "quantity": "0.01",
        //         "amount": "0.0",
        //         "orderType": "LIMIT",
        //         "timeInForce": "GTC",
        //         "createdAt": "1715763507682",
        //         "displayQuantity": "0.01"
        //     }
        //
        // accepted order responseType ACK
        //     {
        //         "accountId": "106490",
        //         "orderId": "1000109892193",
        //         "submitted": true,
        //         "marketCode": "OX-USDT",
        //         "side": "BUY",
        //         "price": "0.01961",
        //         "isTriggered": false,
        //         "quantity": "100",
        //         "orderType": "MARKET",
        //         "timeInForce": "IOC",
        //         "createdAt": "1715591529057",
        //         "selfTradePreventionMode": "NONE"
        //     }
        //
        //  rejected order (balance insufficient)
        //     {
        //         "code": "710001",
        //         "message": "System failure, exception thrown -> null",
        //         "submitted": false,
        //         "marketCode": "OX-USDT",
        //         "side": "BUY",
        //         "price": "0.01961",
        //         "amount": "100",
        //         "orderType": "MARKET",
        //         "timeInForce": "IOC",
        //         "createdAt": "1715591678835",
        //         "source": 11,
        //         "selfTradePreventionMode": "NONE"
        //     }
        //
        // rejected order (bad request)
        //     {
        //         "code": "20044",
        //         "message": "Amount is not supported for this order type",
        //         "submitted": false,
        //         "marketCode": "OX-USDT",
        //         "side": "SELL",
        //         "amount": "200",
        //         "orderType": "MARKET",
        //         "createdAt": "1715592079986",
        //         "source": 11
        //     }
        //
        // fetchOrder
        //     {
        //         "orderId": "1000111762980",
        //         "clientOrderId": "0",
        //         "marketCode": "ETH-USD-SWAP-LIN",
        //         "status": "OPEN",
        //         "side": "BUY",
        //         "price": "2700.0",
        //         "isTriggered": false,
        //         "remainQuantity": "0.01",
        //         "totalQuantity": "0.01",
        //         "amount": "0",
        //         "displayQuantity": "0.01",
        //         "cumulativeMatchedQuantity": "0",
        //         "orderType": "STOP_LIMIT",
        //         "timeInForce": "GTC",
        //         "source": "11",
        //         "createdAt": "1715794191277"
        //     }
        //
        let mut marketId: Value = self.safe_string_k(order.clone(), "marketCode", &[]);
        market = self.safe_market(&[marketId.clone(), market.clone()]);
        let mut timestamp: Value = self.safe_integer_k(order.clone(), "createdAt", &[]);
        let mut fee: Value = Value::Null;
        let mut feeCurrency: Value = self.safe_string_k(order.clone(), "feeInstrumentId", &[]);
        if !is_equal(&feeCurrency, &Value::Null) {
            fee = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("currency".to_string(), self.safe_currency_code(feeCurrency.clone(), &[]));
                    m.insert("cost".to_string(), self.safe_number_k(order.clone(), "fees", &[]));
                m
            });
        }
        let mut status: Value = self.safe_string_k(order.clone(), "status", &[]);
        let mut code: Value = self.safe_integer_k(order.clone(), "code", &[]); // rejected orders have code of the error
        if !is_equal(&code, &Value::Null) {
            status = Value::Str("rejected".to_string());
        }
        let mut triggerPrice: Value = self.safe_string_k(order.clone(), "stopPrice", &[]);
        return self.safe_order(Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("id".to_string(), self.safe_string_k(order.clone(), "orderId", &[]));
        m.insert("clientOrderId".to_string(), self.safe_string_k(order.clone(), "clientOrderId", &[]));
        m.insert("timestamp".to_string(), timestamp.clone());
        m.insert("datetime".to_string(), self.iso8601(timestamp.clone()));
        m.insert("lastTradeTimestamp".to_string(), self.safe_integer_k(order.clone(), "lastMatchedAt", &[]));
        m.insert("lastUpdateTimestamp".to_string(), self.safe_integer_k(order.clone(), "lastModifiedAt", &[]));
        m.insert("status".to_string(), self.parse_order_status(status.clone()));
        m.insert("symbol".to_string(), get_value(&market, &Value::Str("symbol".to_string())));
        m.insert("type".to_string(), self.parse_order_type(self.safe_string_k(order.clone(), "orderType", &[])));
        m.insert("timeInForce".to_string(), self.parse_order_time_in_force(self.safe_string_k(order.clone(), "timeInForce", &[])));
        m.insert("side".to_string(), self.safe_string_lower(order.clone(), Value::Str("side".to_string()), &[]));
        m.insert("price".to_string(), self.safe_string_n(order.clone(), Value::List(vec![Value::Str("price".to_string()), Value::Str("matchPrice".to_string()), Value::Str("limitPrice".to_string())]), &[]));
        m.insert("average".to_string(), Value::Null);
        m.insert("amount".to_string(), self.safe_string2(order.clone(), Value::Str("totalQuantity".to_string()), Value::Str("quantity".to_string()), &[]));
        m.insert("filled".to_string(), self.safe_string2(order.clone(), Value::Str("cumulativeMatchedQuantity".to_string()), Value::Str("matchQuantity".to_string()), &[]));
        m.insert("remaining".to_string(), self.safe_string_k(order.clone(), "remainQuantity", &[]));
        m.insert("triggerPrice".to_string(), triggerPrice.clone());
        m.insert("stopLossPrice".to_string(), triggerPrice.clone());
        m.insert("cost".to_string(), self.omit_zero(self.safe_string_k(order.clone(), "amount", &[])));
        m.insert("trades".to_string(), Value::Null);
        m.insert("fee".to_string(), fee.clone());
        m.insert("info".to_string(), order.clone());
    m
}), &[market.clone()]);

    Value::Null
}

    pub fn parse_order_status(&self, mut status: Value) -> Value {
        let mut statuses: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("OPEN".to_string(), Value::Str("open".to_string()));
                m.insert("PARTIALLY_FILLED".to_string(), Value::Str("open".to_string()));
                m.insert("PARTIAL_FILL".to_string(), Value::Str("open".to_string()));
                m.insert("FILLED".to_string(), Value::Str("closed".to_string()));
                m.insert("CANCELED".to_string(), Value::Str("canceled".to_string()));
                m.insert("CANCELED_BY_USER".to_string(), Value::Str("canceled".to_string()));
                m.insert("CANCELED_BY_MAKER_ONLY".to_string(), Value::Str("rejected".to_string()));
                m.insert("CANCELED_BY_FOK".to_string(), Value::Str("rejected".to_string()));
                m.insert("CANCELED_ALL_BY_IOC".to_string(), Value::Str("rejected".to_string()));
                m.insert("CANCELED_PARTIAL_BY_IOC".to_string(), Value::Str("canceled".to_string()));
                m.insert("CANCELED_BY_SELF_TRADE_PROTECTION".to_string(), Value::Str("rejected".to_string()));
            m
        });
        return self.safe_string(statuses.clone(), status.clone(), &[status.clone()]);

    Value::Null
}

    pub fn parse_order_type(&self, mut type_var: Value) -> Value {
        let mut types: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("LIMIT".to_string(), Value::Str("limit".to_string()));
                m.insert("STOP_LIMIT".to_string(), Value::Str("limit".to_string()));
                m.insert("MARKET".to_string(), Value::Str("market".to_string()));
                m.insert("STOP_MARKET".to_string(), Value::Str("market".to_string()));
            m
        });
        return self.safe_string(types.clone(), type_var.clone(), &[type_var.clone()]);

    Value::Null
}

    pub fn parse_order_time_in_force(&self, mut type_var: Value) -> Value {
        let mut types: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
                m.insert("GTC".to_string(), Value::Str("GTC".to_string()));
                m.insert("IOC".to_string(), Value::Str("IOC".to_string()));
                m.insert("FOK".to_string(), Value::Str("FOK".to_string()));
                m.insert("MAKER_ONLY".to_string(), Value::Str("PO".to_string()));
                m.insert("MAKER_ONLY_REPRICE".to_string(), Value::Str("PO".to_string()));
            m
        });
        return self.safe_string(types.clone(), type_var.clone(), &[type_var.clone()]);

    Value::Null
}

    pub fn sign(&self, mut path: Value, optional_args: &[Value]) -> Value {
        let mut api = get_arg(optional_args, 0, Value::Str("public".to_string()));
        let mut method = get_arg(optional_args, 1, Value::Str("GET".to_string()));
        let mut params = get_arg(optional_args, 2, Value::Map({
    let mut m = indexmap::IndexMap::new();
    m
}));
        let mut headers = get_arg(optional_args, 3, Value::Null);
        let mut body = get_arg(optional_args, 4, Value::Null);
        let mut baseUrl: Value = get_value(&get_value(&self.urls, &Value::Str("api".to_string())), &api);
        let mut url: Value = add(&add(&baseUrl, &Value::Str("/".to_string())), &path);
        let mut queryString: Value = Value::Str("".to_string());
        if is_equal(&method, &Value::Str("GET".to_string())) {
            queryString = self.urlencode(params.clone(), &[]);
            if !is_equal(&get_array_length(&queryString), &Value::Int(0)) {
                url = add(&url, &add(&Value::Str("?".to_string()), &queryString));
            }
        }
        if is_equal(&api, &Value::Str("private".to_string())) {
            self.check_required_credentials(&[]);
            let mut timestamp: Value = self.milliseconds();
            let mut isoDatetime: Value = self.iso8601(timestamp.clone());
            let mut datetimeParts: Value = split(&isoDatetime, &Value::Str(".".to_string()));
            let mut datetime: Value = get_value(&datetimeParts, &Value::Int(0));
            let mut nonce: Value = self.nonce();
            let mut urlParts: Value = split(&baseUrl, &Value::Str("//".to_string()));
            if is_true(&(is_equal(&method, &Value::Str("POST".to_string())))) || is_true(&(is_equal(&method, &Value::Str("DELETE".to_string())))) {
                body = self.json(params.clone());
                queryString = body.clone();
            }
            let mut msgString: Value = add(&add(&add(&add(&add(&add(&add(&add(&add(&add(&datetime, &Value::Str("\n".to_string())), &to_string_val(&nonce)), &Value::Str("\n".to_string())), &method), &Value::Str("\n".to_string())), &get_value(&urlParts, &Value::Int(1))), &Value::Str("\n/".to_string())), &path), &Value::Str("\n".to_string())), &queryString);
            let mut signature: Value = self.hmac(self.encode(msgString.clone()), self.encode(self.secret.clone()), Value::Str("sha256".to_string()), &[Value::Str("base64".to_string())]);
            headers = Value::Map({
                let mut m = indexmap::IndexMap::new();
                    m.insert("Content-Type".to_string(), Value::Str("application/json".to_string()));
                    m.insert("AccessKey".to_string(), self.apiKey.clone());
                    m.insert("Timestamp".to_string(), datetime.clone());
                    m.insert("Signature".to_string(), signature.clone());
                    m.insert("Nonce".to_string(), to_string_val(&nonce));
                m
            });
        }
        return Value::Map({
    let mut m = indexmap::IndexMap::new();
        m.insert("url".to_string(), url.clone());
        m.insert("method".to_string(), method.clone());
        m.insert("body".to_string(), body.clone());
        m.insert("headers".to_string(), headers.clone());
    m
});

    Value::Null
}

    pub fn handle_errors(&self, mut code: Value, mut reason: Value, mut url: Value, mut method: Value, mut headers: Value, mut body: Value, mut response: Value, mut requestHeaders: Value, mut requestBody: Value) -> Value {
        if is_equal(&response, &Value::Null) {
            return Value::Null;
        }
        if !is_equal(&code, &Value::Int(200)) {
            let mut responseCode: Value = self.safe_string_k(response.clone(), "code", &[]);
            let mut feedback: Value = add(&add(&self.id, &Value::Str(" ".to_string())), &body);
            self.throw_broadly_matched_exception(get_value(&self.exceptions, &Value::Str("broad".to_string())), body.clone(), feedback.clone());
            self.throw_exactly_matched_exception(get_value(&self.exceptions, &Value::Str("exact".to_string())), responseCode.clone(), feedback.clone());
            panic!("{}", crate::exchange_errors::exchange_error(feedback));
        }
        return Value::Null;

    Value::Null
}
